4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill single cell due to underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should keep live cell with 2 neighbors", () => {
12	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0]])).toEqual([[0, 0]]);
13	  });
14	  it("should keep live cell with 3 neighbors", () => {
15	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0], [0, 1]])).toEqual([[0, 0]]);
16	  });
17	  it("should kill live cell with 1 neighbor", () => {
18	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
19	  });
20	  it("should kill live cell with 4 neighbors", () => {
21	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0], [0, -1], [0, 1]])).toEqual([]);
22	  });
23	  it("should resurrect dead cell with exactly 3 neighbors", () => {
24	    expect(nextGeneration([[-1, 0], [1, 0], [0, -1]])).toEqual([[0, 0]]);
25	  });
26	  it("should handle multiple live cells in single generation", () => {
27	    // Two vertically-stacked cells with a cell below
28	    // Both survive: each has 1 neighbor (forming a 3-cell line)
29	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toEqual([[0, 0], [0, 1], [0, 2]]);
30	  });
31	});
